import io.quarkus.runtime.Quarkus;
import io.quarkus.runtime.annotations.QuarkusMain;

/**
 * Main application class for the service.
 */
@QuarkusMain
public class MyApplication {

    public static void main(String... args) {
        Quarkus.run(args);
    }
}

